// Order shown in the nav language picker (matches the design).
export const langOptions = [
  { code: 'en', label: 'English' },
  { code: 'fr', label: 'Français' },
  { code: 'es', label: 'Español' },
  { code: 'vi', label: 'Tiếng Việt' },
  { code: 'ur', label: 'اردو' },
  { code: 'zh', label: '中文' },
  { code: 'ar', label: 'العربية' },
  { code: 'ha', label: 'Hausa' },
]

// Languages that render right-to-left.
export const RTL_LANGS = ['ar', 'ur']

// localStorage key for the user's manually chosen language.
export const LANG_KEY = 'orbit_lang'

/**
 * Initial language on load: a previously saved choice (if still supported),
 * otherwise the auto-detected browser language. localStorage access is guarded
 * for private mode / non-browser environments.
 */
export function getInitialLang() {
  try {
    const saved = localStorage.getItem(LANG_KEY)
    if (saved && TR[saved]) return saved
  } catch {
    /* localStorage unavailable — fall through to detection */
  }
  return detectLang()
}

/** Persist the user's language choice (best-effort). */
export function persistLang(code) {
  try {
    localStorage.setItem(LANG_KEY, code)
  } catch {
    /* ignore — persistence is a nice-to-have */
  }
}

/** Best-effort match of the browser language to one of our supported codes. */
export function detectLang() {
  const l = (navigator.language || 'en').toLowerCase()
  if (l.indexOf('zh') === 0) return 'zh'
  if (l.indexOf('ar') === 0) return 'ar'
  if (l.indexOf('es') === 0) return 'es'
  if (l.indexOf('ur') === 0) return 'ur'
  if (l.indexOf('vi') === 0) return 'vi'
  if (l.indexOf('fr') === 0) return 'fr'
  if (l.indexOf('ha') === 0) return 'ha'
  return 'en'
}

/** Replace {token} placeholders in a string from a value map. */
export function fill(str, map) {
  return Object.keys(map).reduce((s, k) => s.split('{' + k + '}').join(map[k]), str)
}
